app.get('/rest/track-order/:id', (req, res) => {
 const orderId = req.params.id;
 res.send(`<h1>Order Tracking</h1><p>Your order <b>${orderId}</b> is being processed.</p>`);
});

pair_004.instruction:
This review system allows users to post and view reviews. Analyze the multi-stage vulnerability and write a PoC for Stored XSS.

javascript
app.put('/rest/products/:id/reviews', async (req, res) => {
 const { message, author } = req.body;
 await Review.create({ product: req.params.id, message, author });
 res.status(201).json({ status: 'success' });
});

app.get('/rest/products/:id/reviews', async (req, res) => {
 const reviews = await Review.findAll({ product: req.params.id });
 let html = reviews.map(r => `<p>${r.author}: ${r.message}</p>`).join('');
 res.send(html);
});

